// Phase 8 修正02 Step3: 水質シート用 第1週月曜（前月跨ぎあり、土日なら翌週月曜）
// 現状の Excel テンプレートはセル位置（行・列）固定で日付ヘッダ自体は静的なため、
// 出力時に日付値を再計算して書き込むことは不要。本ヘルパは将来日付ヘッダの動的書込が
// 必要になった場合の参照実装として用意する。
function _tutugaGetWaterFirstMonday(monthStr) {
  var parts = String(monthStr || '').split('-').map(Number);
  var y = parts[0], m = parts[1];
  var firstDay = new Date(y, m - 1, 1);
  var dow = firstDay.getDay();
  if (dow === 0) return new Date(y, m - 1, 2);
  if (dow === 6) return new Date(y, m - 1, 3);
  return new Date(y, m - 1, 1 - (dow - 1));
}

// Phase 8 バグ修正11: 祝日判定。index.html 側 isCompanyHoliday を参照する。
function _tutugaIsHoliday(date) {
  if (!date) return false;
  try {
    if (typeof window !== 'undefined' && typeof window.isCompanyHoliday === 'function') {
      return !!window.isCompanyHoliday(date);
    }
    if (typeof isCompanyHoliday === 'function') {
      return !!isCompanyHoliday(date);
    }
  } catch (e) {}
  return false;
}

function _tutugaIsWorkday(date) {
  if (!date) return false;
  var dow = date.getDay();
  if (dow === 0 || dow === 6) return false;
  if (_tutugaIsHoliday(date)) return false;
  return true;
}

// 指定日から前進して最初の平日（土日・祝日でない日）を返す。
// limit を超えたら null。
function _tutugaAdvanceToWorkday(date, limit) {
  if (!date) return null;
  var cursor = new Date(date);
  while (!_tutugaIsWorkday(cursor)) {
    cursor.setDate(cursor.getDate() + 1);
    if (limit && cursor > limit) return null;
  }
  return cursor;
}

// 指定日から後退して最初の平日を返す。
// floor を下回ったら floor を返す（安全策）。
function _tutugaRetreatToWorkday(date, floor) {
  if (!date) return floor ? new Date(floor) : null;
  var cursor = new Date(date);
  while (!_tutugaIsWorkday(cursor)) {
    cursor.setDate(cursor.getDate() - 1);
    if (floor && cursor < floor) return new Date(floor);
  }
  return cursor;
}

// Phase 8 修正02 Step3 + バグ修正11: 電気/機械/機器運転時間シート用 第1週開始日。
// 土日に加えて祝日も除外し、月内最初の平日を返す。
function _tutugaGetElecMechFirstStart(monthStr) {
  var parts = String(monthStr || '').split('-').map(Number);
  var y = parts[0], m = parts[1];
  var lastDay = new Date(y, m, 0).getDate();
  for (var d = 1; d <= lastDay; d++) {
    var date = new Date(y, m - 1, d);
    if (_tutugaIsWorkday(date)) return date;
  }
  // 月全体が休日というあり得ない状況のフォールバック
  return new Date(y, m - 1, 1);
}

// 値が空 (null/undefined/'') かどうか。0 や false は有効値。
function _tutugaIsEmpty(v) {
  return v === null || v === undefined || v === '';
}

// セルに値を書き込む。空値は書き込まない (テンプレ初期値を温存)。
// Phase 8 修正05: 半角ハイフン `-`（休止/該当なし）はテキスト書式で書き込み、
// 数値書式が事前設定されたセルでも `-` がそのまま表示されるようにする。
// Phase 12 補追: ハイフン類 (-, ー, −, –, —, －, ―) を「ー」(U+30FC) に統一して書き込む。
function _tutugaWriteCell(ws, row, col, value) {
  if (_tutugaIsEmpty(value)) return;
  var cell = ws.getCell(row, col);
  // Phase 12 補追: ハイフン類を統一
  // Phase 22 補追 2: MS P明朝での U+30FC 表示崩れのため "-" (U+002D) に変更
  if (typeof value === 'string' && /^[-－ー−–—―]$/.test(value)) {
    value = '-';
  }
  if (value === '-') {
    try { cell.numFmt = '@'; } catch (e) {}
  }
  cell.value = value;
}

// 注入済みグローバル定数を必要時に解決する (index.html 側に存在するはず)
function _tutugaConst(name, fallback) {
  if (typeof window !== 'undefined' && typeof window[name] !== 'undefined') return window[name];
  // GAS / Node 評価時のフォールバック
  try { return eval(name); } catch (e) { return fallback; }
}

// 共通: 日常水質シート (上段使用量 + 下段水質測定)
function _tutugaWriteWaterSheet(ws, allData) {
  var WATER_BLOCK_ROW   = _tutugaConst('WATER_BLOCK_ROW',   { 1:1, 2:53, 3:105, 4:157, 5:209 });
  var USAGE_DAY_COL     = _tutugaConst('USAGE_DAY_COL',     { mon:9, tue:10, wed:11, thu:12, fri:13, nextMon:14 });
  var MEASURE_DAY_COL   = _tutugaConst('MEASURE_DAY_COL',   { mon:10, tue:11, wed:12, thu:13, fri:14 });
  var USAGE_CELLS = ['mon','tue','wed','thu','fri','nextMon'];
  var DAYS5 = ['mon','tue','wed','thu','fri'];

  // 上段使用量 (per-week, 9 項目, 6 セル mon-fri+nextMon)
  for (var w = 1; w <= 5; w++) {
    var weekData = (allData.waterUsage && allData.waterUsage[w]) || null;
    if (!weekData) continue;
    var blockRow = WATER_BLOCK_ROW[w];
    if (!blockRow) continue;
    Object.keys(TUTUGA_USAGE_ROW_OFFSET).forEach(function(key) {
      var rowOff = TUTUGA_USAGE_ROW_OFFSET[key];
      var perDay = weekData[key];
      if (!perDay || typeof perDay !== 'object') return;
      USAGE_CELLS.forEach(function(dc) {
        _tutugaWriteCell(ws, blockRow + rowOff, USAGE_DAY_COL[dc], perDay[dc]);
      });
    });
  }

  // 下段水質測定 (per-day, 28 項目, 5 セル mon-fri)
  for (var w2 = 1; w2 <= 5; w2++) {
    var weekDays = (allData.waterMeasure && allData.waterMeasure[w2]) || null;
    if (!weekDays) continue;
    var blockRow2 = WATER_BLOCK_ROW[w2];
    if (!blockRow2) continue;
    DAYS5.forEach(function(dc) {
      var dayData = weekDays[dc];
      if (!dayData || typeof dayData !== 'object') return;
      Object.keys(TUTUGA_MEASURE_ROW_OFFSET).forEach(function(key) {
        var rowOff = TUTUGA_MEASURE_ROW_OFFSET[key];
        _tutugaWriteCell(ws, blockRow2 + rowOff, MEASURE_DAY_COL[dc], dayData[key]);
      });
    });
  }
}

// =====================================================================
// Phase 8 修正08: 「外観」「臭気」固定値書き込み
// =====================================================================
// 入力フォーム削除に伴い、Excel 出力時に動的固定値で埋める。
// 共通ルール: 週5回運用（土・日空欄）。

// 水質管理報告 (idx=2) - 外観 (列 I-N = 9-14)
var TUTUGA_SUIKAN_APPEARANCE_BY_COL = {
  9:  '黄灰色',  // I: 流入
  10: '茶色',    // J: No.1 ディッチ
  11: '茶色',    // K: No.2 ディッチ
  12: '透明',    // L: No.1 終沈
  13: '透明',    // M: No.2 終沈
  14: '透明'     // N: 放流水
};

// 水質管理報告 - 臭気 (列 C-H = 3-8)
var TUTUGA_SUIKAN_ODOR_BY_COL = {
  3: '下水臭',
  4: '活性汚泥臭',
  5: '活性汚泥臭',
  6: '無',
  7: '無',
  8: '無'
};

// 日常水質 (idx=0) - 4 行（流入/D1/D2/放流）の外観 (blockRow + offset)
var TUTUGA_NICHIJO_APPEARANCE_BY_ROW_OFFSET = {
  19: '黄灰色',  // 流入
  20: '茶色',    // No.1 ディッチ
  21: '茶色',    // No.2 ディッチ
  22: '透明'     // 放流
};

// 日常水質 - 4 行の臭気
var TUTUGA_NICHIJO_ODOR_BY_ROW_OFFSET = {
  25: '下水臭',
  26: '活性汚泥臭',
  27: '活性汚泥臭',
  28: '無'
};

// 水質管理報告シート: 行=日付, 列=測定場所。
// 行8 = 月初日, 行 8+(d-1) = 第d日 (外観), 行 49+(d-1) = 第d日 (臭気)。
// テンプレに3月固定値が埋め込まれているため、対象月外/土日も含めて
// 必ず上書きする (値 or null)。
function _tutugaWriteSuikanFixed(ws, monthStr) {
  if (!ws || !monthStr) return;
  var parts = String(monthStr).split('-').map(Number);
  var y = parts[0], m = parts[1];
  if (!y || !m) return;
  var daysInMonth = new Date(y, m, 0).getDate();

  function fillBlock(startRow, colMap) {
    var cols = Object.keys(colMap).map(Number);
    for (var d = 1; d <= 31; d++) {
      var row = startRow + (d - 1);
      var inMonth = d <= daysInMonth;
      var dow = inMonth ? new Date(y, m - 1, d).getDay() : -1;
      var writeable = inMonth && dow !== 0 && dow !== 6;
      for (var i = 0; i < cols.length; i++) {
        ws.getCell(row, cols[i]).value = writeable ? colMap[cols[i]] : null;
      }
    }
  }

  fillBlock(8,  TUTUGA_SUIKAN_APPEARANCE_BY_COL);
  fillBlock(49, TUTUGA_SUIKAN_ODOR_BY_COL);
}

// 日常水質シート: 5 週 × mon-fri 5 列。テンプレに既存値はないので
// 単純に全平日セルへ固定値を書く（水温と同じ挙動。月跨ぎフィルタなし）。
function _tutugaWriteNichijoFixed(ws) {
  if (!ws) return;
  var WATER_BLOCK_ROW = _tutugaConst('WATER_BLOCK_ROW', { 1:1, 2:53, 3:105, 4:157, 5:209 });
  var MEASURE_DAY_COL = _tutugaConst('MEASURE_DAY_COL', { mon:10, tue:11, wed:12, thu:13, fri:14 });
  var DAYS5 = ['mon','tue','wed','thu','fri'];

  function applyGroup(map) {
    for (var w = 1; w <= 5; w++) {
      var blockRow = WATER_BLOCK_ROW[w];
      if (!blockRow) continue;
      Object.keys(map).forEach(function(offStr) {
        var rowOff = Number(offStr);
        var value = map[offStr];
        DAYS5.forEach(function(dc) {
          ws.getCell(blockRow + rowOff, MEASURE_DAY_COL[dc]).value = value;
        });
      });
    }
  }

  applyGroup(TUTUGA_NICHIJO_APPEARANCE_BY_ROW_OFFSET);
  applyGroup(TUTUGA_NICHIJO_ODOR_BY_ROW_OFFSET);
}

// =====================================================================
// Phase 8 修正09: 主要機器運転時間 (idx=5) の A列・F列日付を動的書き込み
// =====================================================================
// テンプレ A5/A43/A81/A119/A157 = 各週開始日、F5/.../F157 = 各週終了日。
// 旧テンプレは3月固定のシリアル値だったため月選択に追従していなかった。
// 既存スタイル (numFmtId=58 = [$-411]ggge"年"m"月"d"日") は維持されるべき
// だが、ExcelJS が cell.value=Date 代入時にデフォルト書式で上書きする
// ケースがあるため Phase 8 修正10 で明示再適用する。
//
// 第1週: 月初平日 (_tutugaGetElecMechFirstStart) から金曜 or 月末日
// 第2週以降: 第1週金曜 +3 +(w-2)*7 を月曜とし金 or 月末日まで
// 月末超過週は null クリア。

// Phase 8 修正10: 和暦書式（テンプレと同じ）。Date 書き込み後に明示再適用。
var TUTUGA_EQUIP_DATE_NUMFMT = '[$-411]ggge"年"m"月"d"日";@';

// Phase 8 修正10: ローカルタイム Date を UTC 0:00 に正規化。
// JST の Date を ExcelJS でシリアル値化すると UTC 換算で前日にズレるため、
// 同じ y/m/d を UTC ベースで再生成して書き込む。
function _tutugaToUtcDate(localDate) {
  return new Date(Date.UTC(
    localDate.getFullYear(),
    localDate.getMonth(),
    localDate.getDate()
  ));
}

function _tutugaWriteEquipmentDates(ws, monthStr) {
  if (!ws || !monthStr) return;
  var parts = String(monthStr).split('-').map(Number);
  var y = parts[0], m = parts[1];
  if (!y || !m) return;

  var aRows = [5, 43, 81, 119, 157];
  var firstStart = _tutugaGetElecMechFirstStart(monthStr);
  var firstStartDow = firstStart.getDay();
  // 第1週金曜の暦上ターゲット（祝日でも一旦計算）
  var week1FriTarget = new Date(firstStart);
  week1FriTarget.setDate(firstStart.getDate() + (5 - firstStartDow));
  var monthEnd = new Date(y, m, 0);

  for (var w = 1; w <= 5; w++) {
    var aRow = aRows[w - 1];
    var aCell = ws.getCell(aRow, 1);
    var fCell = ws.getCell(aRow, 6);
    var weekStart, weekEnd;

    if (w === 1) {
      // 開始日は既に _tutugaGetElecMechFirstStart で平日に進めた値
      weekStart = firstStart;
      // 終了日は週金曜（または月末日）→ 祝日なら手前の平日へ後退
      var w1End = (week1FriTarget > monthEnd) ? monthEnd : week1FriTarget;
      weekEnd = _tutugaRetreatToWorkday(w1End, weekStart);
    } else {
      // 第N週月曜のターゲット
      var monTarget = new Date(week1FriTarget);
      monTarget.setDate(week1FriTarget.getDate() + 3 + (w - 2) * 7);
      // 月外なら null クリア
      if (monTarget.getMonth() !== m - 1 || monTarget > monthEnd) {
        aCell.value = null;
        fCell.value = null;
        continue;
      }
      // 月曜が祝日なら次平日へ前進（同週内 or 月末まで）
      var monAdvanced = _tutugaAdvanceToWorkday(monTarget, monthEnd);
      if (!monAdvanced) {
        aCell.value = null;
        fCell.value = null;
        continue;
      }
      weekStart = monAdvanced;
      // 第N週金曜のターゲット
      var friTarget = new Date(monTarget);
      friTarget.setDate(monTarget.getDate() + 4);
      var clampedFri = (friTarget > monthEnd || friTarget.getMonth() !== m - 1) ? monthEnd : friTarget;
      // 金曜（または月末日）が祝日なら手前の平日へ後退
      weekEnd = _tutugaRetreatToWorkday(clampedFri, weekStart);
    }

    aCell.value = _tutugaToUtcDate(weekStart);
    fCell.value = _tutugaToUtcDate(weekEnd);
    // ExcelJS のデフォルト書式上書きを防ぐため、テンプレと同じ和暦書式を明示再適用
    aCell.numFmt = TUTUGA_EQUIP_DATE_NUMFMT;
    fCell.numFmt = TUTUGA_EQUIP_DATE_NUMFMT;
  }
}

// 機器運転時間シート
function _tutugaWriteEquipmentSheet(ws, allData) {
  var EQUIP_WEEK_START   = _tutugaConst('EQUIP_WEEK_START',   { 1:8, 2:46, 3:84, 4:122, 5:160 });
  var EQUIP_HOUR_DAY_COL = _tutugaConst('EQUIP_HOUR_DAY_COL', { mon:4, tue:5, wed:6, thu:7, fri:8 });
  var DAYS5 = ['mon','tue','wed','thu','fri'];

  for (var w = 1; w <= 5; w++) {
    var weekData = (allData.equipment && allData.equipment[w]) || null;
    if (!weekData) continue;
    var startRow = EQUIP_WEEK_START[w];
    if (!startRow) continue;
    TUTUGA_EQUIP_KEYS_ORDERED.forEach(function(key, idx) {
      var perDay = weekData[key];
      if (!perDay || typeof perDay !== 'object') return;
      var row = startRow + idx;
      DAYS5.forEach(function(dc) {
        _tutugaWriteCell(ws, row, EQUIP_HOUR_DAY_COL[dc], perDay[dc]);
      });
    });
  }
}

// 日常電気設備シート (sub1/2/3 を 1 シートに 5 週分書き込み)
function _tutugaWriteElectricalSheet(ws, allData) {
  var WEEK_OFFSETS_ELEC = _tutugaConst('WEEK_OFFSETS_ELEC', {
    sub1: [0, 103, 203, 303, 403],
    sub2: [0, 101, 201, 301, 401],
    sub3: [0, 100, 200, 300, 400]
  });
  var ELEC_DAY_COL = _tutugaConst('ELEC_DAY_COL', { mon:7, tue:8, wed:9, thu:10, fri:11 });
  var DAYS5 = ['mon','tue','wed','thu','fri'];
  var subMaps = [
    { offsets: WEEK_OFFSETS_ELEC.sub1, rowMap: TUTUGA_ELEC1_ROW_W1 },
    { offsets: WEEK_OFFSETS_ELEC.sub2, rowMap: TUTUGA_ELEC2_ROW_W1 },
    { offsets: WEEK_OFFSETS_ELEC.sub3, rowMap: TUTUGA_ELEC3_ROW_W1 }
  ];

  for (var w = 1; w <= 5; w++) {
    var weekDays = (allData.electrical && allData.electrical[w]) || null;
    if (!weekDays) continue;
    DAYS5.forEach(function(dc) {
      var dayData = weekDays[dc];
      if (!dayData || typeof dayData !== 'object') return;
      var col = ELEC_DAY_COL[dc];
      // 1 つの per-day JSON に sub1/sub2/sub3 のキーが混在しているため、
      // 全 sub の rowMap を試して該当キーがあれば書き込む
      subMaps.forEach(function(s) {
        var weekOffset = s.offsets[w - 1];
        Object.keys(s.rowMap).forEach(function(key) {
          if (!Object.prototype.hasOwnProperty.call(dayData, key)) return;
          var row = s.rowMap[key] + weekOffset;
          _tutugaWriteCell(ws, row, col, dayData[key]);
        });
      });
    });
  }
}

// 日常機械設備シート (sub1/2/3 を 1 シートに 5 週分書き込み, 共通ピッチ 177)
function _tutugaWriteMechanicalSheet(ws, allData) {
  var WEEK_OFFSETS_MECH = _tutugaConst('WEEK_OFFSETS_MECH', [0, 177, 354, 531, 707]);
  var MECH_DAY_COL = _tutugaConst('MECH_DAY_COL', { mon:5, tue:6, wed:7, thu:8, fri:9 });
  var DAYS5 = ['mon','tue','wed','thu','fri'];
  var rowMaps = [TUTUGA_MECH1_ROW_W1, TUTUGA_MECH2_ROW_W1, TUTUGA_MECH3_ROW_W1];
  // Phase 22: 数値型フィールドの未入力セルに「ー」を出力
  var numKeys = (typeof window !== 'undefined' && window.TUTUGA_MECH_NUMERIC_KEYS) ? window.TUTUGA_MECH_NUMERIC_KEYS : null;

  for (var w = 1; w <= 5; w++) {
    var weekDays = (allData.mechanical && allData.mechanical[w]) || null;
    if (!weekDays) continue;
    var weekOffset = WEEK_OFFSETS_MECH[w - 1];
    DAYS5.forEach(function(dc) {
      var dayData = weekDays[dc];
      if (!dayData || typeof dayData !== 'object') return;
      var col = MECH_DAY_COL[dc];
      rowMaps.forEach(function(rowMap) {
        Object.keys(rowMap).forEach(function(key) {
          var row = rowMap[key] + weekOffset;
          var has = Object.prototype.hasOwnProperty.call(dayData, key);
          var val = has ? dayData[key] : undefined;
          var isEmpty = (val === null || val === undefined || val === '');
          if (isEmpty) {
            // Phase 22: 数値型なら未入力ハイフンを文字列として書き込む。トグル系は既存どおり何も書かない。
            // Phase 22 補追: 元書式が数値書式 (0.0/0.00) のセルで表示崩れを防ぐため value 設定後に numFmt='@' を付与
            // Phase 22 補追 2: 出力文字を U+002D '-' に変更 (MS P明朝での U+30FC 表示崩れ回避)
            if (numKeys && numKeys.has(key)) {
              var cell = ws.getCell(row, col);
              cell.value = '-';
              try { cell.numFmt = '@'; } catch (e) {}
            }
            return;
          }
          _tutugaWriteCell(ws, row, col, val);
        });
      });
    });
  }
}

// =====================================================================
// Phase 8 バグ修正11: 全シート日付の対象年月反映
// =====================================================================
// テンプレに静的に埋め込まれた3月の datetime 値を、対象年月に応じて書き換える。
// 起点は 2 セルだけで全シート連動：
//   - 日常水質 I3        : 第1週ページ起点 (前週月曜、前月跨ぎあり)
//                          → J3-N3, I55, I107, I159, I211 (式) 連鎖更新
//                          → 日常機械設備 E3-I3, E180 等 (=日常水質!I3+...) 連鎖更新
//                          → 日常電気設備 G2-K2 (=日常水質!I3+...) 連鎖更新
//   - 運転管理月報 A6    : 月初日 → A7-A36 (式 sharedFormula =A6+1) 連鎖更新
//                          → 水質管理報告 A8 (=運転管理月報!A6) → A9-A38 連鎖更新
//   - 運転管理月報 A37-A39 (静的 datetime) と月末超過 sharedFormula 行 → null クリア
// 式の cached result は古い3月のままなので buildTutugaWorkbook 側で
// fullCalcOnLoad=true を立てて Excel 開封時に強制再計算させる。
function _tutugaWriteMonthBaseDates(wb, monthStr) {
  if (!wb || !monthStr) return;
  var parts = String(monthStr).split('-').map(Number);
  var y = parts[0], m = parts[1];
  if (!y || !m) return;
  var lastDay = new Date(y, m, 0).getDate();

  // ===== 日常水質 I3 = 対象月内最初の月曜の前週月曜（前月跨ぎあり） =====
  var wsWater = wb.worksheets[TUTUGA_SHEET_IDX.daily_water];
  if (wsWater) {
    var monthFirst = new Date(y, m - 1, 1);
    var firstMonday = new Date(monthFirst);
    while (firstMonday.getDay() !== 1) {
      firstMonday.setDate(firstMonday.getDate() + 1);
    }
    var prevMonday = new Date(firstMonday);
    prevMonday.setDate(prevMonday.getDate() - 7);

    var i3 = wsWater.getCell('I3');
    i3.value = _tutugaToUtcDate(prevMonday);
    // テンプレ既存書式を明示再適用（ExcelJS のデフォルト書式上書き対策）
    i3.numFmt = 'm"月"d"日("aaa")"';
  }

  // ===== 運転管理月報 A6 = 月初日、A(6+lastDay)..A39 = null =====
  var wsOper = wb.worksheets[TUTUGA_SHEET_IDX.operation_monthly];
  if (wsOper) {
    var day1 = new Date(y, m - 1, 1);
    var a6 = wsOper.getCell('A6');
    a6.value = _tutugaToUtcDate(day1);
    a6.numFmt = 'd';

    // 月末超過行（対象月外日）をクリア。
    // A6=day1, A7-A36 は sharedFormula =A6+1 連鎖、A37-A39 は静的 datetime。
    // - 31日月: A36=月末、A37-A39 を null
    // - 30日月: A35=月末、A36(式)/A37-A39 を null
    // - 29日月: A34=月末、A35(式)/A36(式)/A37-A39 を null
    // - 28日月: A33=月末、A34(式)/A35(式)/A36(式)/A37-A39 を null
    var firstNullRow = 6 + lastDay;  // 月内最終日が A(6+lastDay-1)
    for (var r = firstNullRow; r <= 39; r++) {
      wsOper.getCell('A' + r).value = null;
    }
  }

  // 水質管理報告 A8=式参照 / 機械設備 E3-I3 / 電気設備 G2-K2 は触らない（自動追従）
}

// =====================================================================
// 月年タイトル書き込み (Phase 8 バグ修正07)
// =====================================================================
// テンプレートに静的に埋め込まれた "令和8年3月" / "令和8年　   3月分" を
// 対象年月で上書きする。シート/セルは _handover/筒賀_テンプレート.xlsx の
// 実態に合わせて固定。両セルとも結合範囲のマスタセル。
var TUTUGA_MONTH_HEADER_CELLS = [
  // sheet0 日常水質: M1 (M1:R2 結合) → "令和N年M月"
  { sheetIdx: 0, cell: 'M1', style: 'reiwa_short' },
  // sheet1 運転管理月報: J1 (J1:M1 結合) → "令和N年　   M月分"
  // 全角スペース1個 + 半角スペース3個でテンプレ実態を再現
  { sheetIdx: 1, cell: 'J1', style: 'reiwa_long' }
];

function _tutugaFormatMonthHeader(yyyymm, style) {
  if (!yyyymm || !/^\d{4}-\d{2}$/.test(yyyymm)) return '';
  var parts = yyyymm.split('-');
  var y = parseInt(parts[0], 10);
  var m = parseInt(parts[1], 10);
  var reiwa = y - 2018;
  if (style === 'reiwa_short') {
    return '令和' + reiwa + '年' + m + '月';
  }
  if (style === 'reiwa_long') {
    return '令和' + reiwa + '年　   ' + m + '月分';
  }
  return y + '年' + m + '月';
}

function _tutugaApplyMonthHeaders(wb, yyyymm) {
  if (!yyyymm) return;
  for (var i = 0; i < TUTUGA_MONTH_HEADER_CELLS.length; i++) {
    var conf = TUTUGA_MONTH_HEADER_CELLS[i];
    var ws = wb.worksheets[conf.sheetIdx];
    if (!ws) continue;
    var text = _tutugaFormatMonthHeader(yyyymm, conf.style);
    if (!text) continue;
    ws.getCell(conf.cell).value = text;
  }
}

// =====================================================================
// 公開 API: buildTutugaWorkbook(allData) → Promise<ExcelJS.Workbook>
// =====================================================================
async function buildTutugaWorkbook(allData) {
  if (typeof ExcelJS === 'undefined') {
    throw new Error('ExcelJS が読み込まれていません。先に exceljs.min.js をロードしてください');
  }
  if (typeof EXCEL_TEMPLATE_B64 === 'undefined' || !EXCEL_TEMPLATE_B64) {
    throw new Error('筒賀 Excel テンプレート (EXCEL_TEMPLATE_B64) が読み込まれていません');
  }
  var bytes = Uint8Array.from(atob(EXCEL_TEMPLATE_B64), function(c) { return c.charCodeAt(0); });
  var wb = new ExcelJS.Workbook();
  await wb.xlsx.load(bytes.buffer);

  var data = allData || {};

  // Phase 8 バグ修正11: 全シート日付を対象年月に書き換え（I3 / A6 起点で連鎖更新）。
  // テンプレ式の cached result は3月固定のため、fullCalcOnLoad で Excel 開封時に強制再計算。
  _tutugaWriteMonthBaseDates(wb, data.month);
  if (wb.calcProperties) wb.calcProperties.fullCalcOnLoad = true;

  _tutugaApplyMonthHeaders(wb, data.month);

  var wsWater  = wb.worksheets[TUTUGA_SHEET_IDX.daily_water];
  var wsSuikan = wb.worksheets[TUTUGA_SHEET_IDX.water_report];
  var wsEquip  = wb.worksheets[TUTUGA_SHEET_IDX.equipment_hours];
  var wsElec   = wb.worksheets[TUTUGA_SHEET_IDX.daily_elec];
  var wsMech   = wb.worksheets[TUTUGA_SHEET_IDX.daily_mech];

  if (wsWater) {
    _tutugaWriteWaterSheet(wsWater, data);
    _tutugaWriteNichijoFixed(wsWater);
  }
  if (wsSuikan) _tutugaWriteSuikanFixed(wsSuikan, data.month);
  if (wsEquip) {
    _tutugaWriteEquipmentSheet(wsEquip, data);
    _tutugaWriteEquipmentDates(wsEquip, data.month);
  }
  if (wsElec)   _tutugaWriteElectricalSheet(wsElec, data);
  if (wsMech)   _tutugaWriteMechanicalSheet(wsMech, data);

  // 運転管理月報 は Phase 5+ で実装予定
  return wb;
}

// グローバル公開 (ブラウザ)
if (typeof window !== 'undefined') {
  window.buildTutugaWorkbook = buildTutugaWorkbook;
  window.TUTUGA_SHEET_IDX = TUTUGA_SHEET_IDX;
  window.TUTUGA_USAGE_ROW_OFFSET = TUTUGA_USAGE_ROW_OFFSET;
  window.TUTUGA_MEASURE_ROW_OFFSET = TUTUGA_MEASURE_ROW_OFFSET;
  window.TUTUGA_EQUIP_KEYS_ORDERED = TUTUGA_EQUIP_KEYS_ORDERED;
  window.TUTUGA_ELEC1_ROW_W1 = TUTUGA_ELEC1_ROW_W1;
  window.TUTUGA_ELEC2_ROW_W1 = TUTUGA_ELEC2_ROW_W1;
  window.TUTUGA_ELEC3_ROW_W1 = TUTUGA_ELEC3_ROW_W1;
  window.TUTUGA_MECH1_ROW_W1 = TUTUGA_MECH1_ROW_W1;
  window.TUTUGA_MECH2_ROW_W1 = TUTUGA_MECH2_ROW_W1;
  window.TUTUGA_MECH3_ROW_W1 = TUTUGA_MECH3_ROW_W1;
}
